1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function isComponentBlock(items: any[]): boolean {
13	  return items.length === 3 && items.every((i) => i.type === items[0].type);
14	}
15	
16	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
17	  rune: 60,
18	};
19	
20	function calculateBasePremium(items: any[]): number {
21	  if (isComponentBlock(items)) {
22	    return COMPONENT_BLOCK_PREMIUM[items[0].type];
23	  }
24	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
25	}
26	
27	function calculatePremium(items: any[]): number {
28	  const basePremium = calculateBasePremium(items);
29	  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
30	}
31	
32	export function processScenario(scenario: any): unknown {
33	  const { items } = scenario.steps[0];
34	  const premium = calculatePremium(items);
35	
36	  return { results: [{ premium }] };
37	}
